import{_ as t,c as e,o as a,N as o}from"./chunks/framework.Sw95nWd2.js";const p=JSON.parse('{"title":"Instant Finality","description":"","frontmatter":{"title":"Instant Finality","outline":[0,4],"order":-100},"headers":[],"relativePath":"blockchain/general/antelope-ultra/finality.md","filePath":"blockchain/general/antelope-ultra/finality.md","lastUpdated":null}'),r={name:"blockchain/general/antelope-ultra/finality.md"},n=o('<h1 id="instant-finality" tabindex="-1">Instant Finality <a class="header-anchor" href="#instant-finality" aria-label="Permalink to &quot;Instant Finality&quot;">​</a></h1><p>Ultra now delivers <strong>Instant Finality</strong>: transactions become <strong>irreversibly final in about 1 second</strong>, down from the multiple minutes required by the previous consensus. It was activated on Mainnet as part of the <strong>Antelope Spring 1.x</strong> upgrade.</p><div class="info custom-block"><p class="custom-block-title">TL;DR</p><p><strong>Before:</strong> a transaction took up to ~3 minutes to become irreversible. <strong>Now:</strong> ~1 second — a <strong>greater than 100x improvement</strong> in time-to-finality, with stronger, cryptographic security guarantees.</p></div><h2 id="what-finality-means" tabindex="-1">What &quot;finality&quot; means <a class="header-anchor" href="#what-finality-means" aria-label="Permalink to &quot;What &quot;finality&quot; means&quot;">​</a></h2><p>Finality is the moment a transaction becomes <strong>permanent and irreversible</strong> — it can never be undone or rolled back by a chain reorganization. Until a transaction is final, anyone relying on it (an exchange, a marketplace, a game) must wait to be safe. Faster finality makes everything faster <em>and</em> safer.</p><h2 id="why-it-matters" tabindex="-1">Why it matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why it matters&quot;">​</a></h2><h3 id="for-everyone" tabindex="-1">For everyone <a class="header-anchor" href="#for-everyone" aria-label="Permalink to &quot;For everyone&quot;">​</a></h3><ul><li><strong>Near-instant settlement.</strong> Payments, token transfers, NFT/Uniq trades, and in-game actions are locked in within ~1 second.</li><li><strong>A web2-like experience.</strong> No more watching a spinner for minutes — confirmations feel instant.</li><li><strong>Stronger guarantees.</strong> Once a transaction is final, it is mathematically irreversible — not just &quot;probably&quot; safe.</li></ul><h3 id="for-developers" tabindex="-1">For developers <a class="header-anchor" href="#for-developers" aria-label="Permalink to &quot;For developers&quot;">​</a></h3><ul><li><strong>Instant-confirmation UX.</strong> React the moment a transaction is final, instead of polling through long &quot;pending&quot; states.</li><li><strong>Faster deposits &amp; withdrawals.</strong> Exchanges and bridges can credit Ultra transactions in ~1 second instead of minutes, cutting settlement risk.</li><li><strong>Simpler logic.</strong> Deterministic finality removes the guesswork of &quot;how many confirmations are safe enough.&quot;</li><li><strong>No migration required.</strong> Your existing contracts and dApps simply finalize faster — no code changes needed.</li></ul><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Instant Finality is powered by <strong>Savanna</strong>, a <strong>Byzantine Fault Tolerant (BFT)</strong> consensus protocol (inspired by the HotStuff algorithm). It separates two responsibilities that used to belong to a single role:</p><ul><li><strong>Block Proposers</strong> produce blocks, as before.</li><li><strong>Block Finalizers</strong> vote on blocks by signing them.</li></ul><p>Finalizer votes use <strong>BLS signatures</strong>, which aggregate into a single compact <strong>Quorum Certificate</strong> (verified in ~1.1 ms). Once a supermajority of finalizers has signed a block, that block is <strong>final</strong> — cryptographically and permanently.</p><div class="info custom-block"><p class="custom-block-title">Ultra still uses Proof of Authority</p><p>Instant Finality changes <em>how fast</em> blocks become final — it does <strong>not</strong> change <em>who</em> produces them. Ultra continues to use <a href="./consensus.html#proof-of-authority-poa">Proof of Authority</a> with its carefully selected Block Producers; the Savanna protocol provides this finality layer on top.</p></div><h2 id="compared-to-the-previous-protocol" tabindex="-1">Compared to the previous protocol <a class="header-anchor" href="#compared-to-the-previous-protocol" aria-label="Permalink to &quot;Compared to the previous protocol&quot;">​</a></h2><table><thead><tr><th></th><th>Before (legacy)</th><th>Now</th></tr></thead><tbody><tr><td>Time to finality</td><td>up to ~3 minutes</td><td><strong>~1 second</strong></td></tr><tr><td>Finality type</td><td>delayed confirmation</td><td><strong>cryptographic &amp; deterministic</strong></td></tr><tr><td>Producer roles</td><td>single role</td><td>Proposers + Finalizers</td></tr><tr><td>Scaling producers</td><td>slowed finality</td><td>add producers without slowing finality</td></tr></tbody></table><h2 id="ultra-vs-other-blockchains" tabindex="-1">Ultra vs. other blockchains <a class="header-anchor" href="#ultra-vs-other-blockchains" aria-label="Permalink to &quot;Ultra vs. other blockchains&quot;">​</a></h2><p>Finality is where Ultra stands apart. Compared with other major chains:</p><table><thead><tr><th>Blockchain</th><th>Time to finality</th><th>Finality type</th></tr></thead><tbody><tr><td>Ethereum</td><td>~13–15 minutes</td><td>deterministic</td></tr><tr><td>Solana</td><td>~13 seconds</td><td>deterministic (BFT)</td></tr><tr><td><strong>Ultra</strong></td><td><strong>~1 second</strong></td><td><strong>deterministic (BFT)</strong></td></tr></tbody></table><p><em>Figures are typical real-world values and vary with network conditions.</em></p><h2 id="is-it-secure" tabindex="-1">Is it secure? <a class="header-anchor" href="#is-it-secure" aria-label="Permalink to &quot;Is it secure?&quot;">​</a></h2><p>Yes — more secure than before. Instant Finality provides <strong>deterministic</strong> finality backed by BFT cryptography: a block is final only after a supermajority of finalizers has cryptographically signed it, and a final block can never be reverted. This is a stronger guarantee than the <strong>probabilistic</strong> finality used by chains like Bitcoin, where &quot;final&quot; only ever means &quot;extremely unlikely to be reversed.&quot;</p><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h2><ul><li><a href="./consensus.html">Consensus</a> — how Ultra&#39;s Proof of Authority works</li><li><a href="./block-production.html">Block Production</a> — how blocks are produced on Ultra</li></ul>',25),i=[n];function s(l,c,d,h,u,g){return a(),e("div",null,i)}const f=t(r,[["render",s]]);export{p as __pageData,f as default};
